var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"이 정도 위력일 줄은…….","JPN":"これ程の威力だったなんて……","ENG":"Didn't think it'd be this powerful...","TWN":"沒想到威力這麼……"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"노엘까지 휩쓸릴 뻔했어. 이렇게까지 할 생각은 없었는데…….","JPN":"ノエルまで巻き込まれるところだったわ。ここまでするつもりはなかったのに……","ENG":"It almost took out Noelle. I wasn't planning on going this far...","TWN":"連洛艾兒都差點掃到，我沒想到會這樣……"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"적은! 적은 어떻게 됐지!?","JPN":"敵は！　敵はどうなったの！？","ENG":"The enemy! Where is she?!","TWN":"敵人呢！敵人怎麼樣了！？"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"움직이지 마!! 양손을 머리 위로 올려!!","JPN":"動くな！！　両手を頭の上に上げろ！！","ENG":"Don't move!! Hands in the air!!","TWN":"不准動！！雙手舉高！！"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"당신들은……?","JPN":"あなたたちは……？","ENG":"You're...?","TWN":"你們是……？"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"형제의 상태는?","JPN":"兄弟の状態は？","ENG":"How's our brother doing?","TWN":"兄弟情況如何？"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"틀렸어. 몸의 절반이 흔적조차 없이 증발해 버렸어.","JPN":"ダメだ。身体の半分が跡もなく蒸発してしまった。","ENG":"She's gone. Half of her body vanished without a trace.","TWN":"不太好，她的身體有一半都不留痕跡地蒸發掉了。"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"끔찍하군. 직격으로 맞았으면 고통을 느끼기도 전에 분해되어 버렸을 거야.","JPN":"ひどいな。直撃していたら、苦痛を感じる前に分解されていただろう。","ENG":"How horrible. If it was a direct hit, she would've dissolved before feeling any pain.","TWN":"真是驚人，要是直接打中她，說不定就直接人間蒸發。"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"이상하군. 어떻게 저런 물건이 민간에 돌아다니고 있는 거지?","JPN":"おかしいな。どうしてあんな物が民間に出回ってるんだ？","ENG":"That's odd. How did something like that fall into the hands of a civilian?","TWN":"奇怪，那種東西怎麼會落在民間？"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"보아하니 미완성이라 출력을 조절할 수 없는 것 같군.","JPN":"どうやら未完成で、出力を調節できないようだな。","ENG":"It also seems that she can't control the output because it's incomplete.","TWN":"看起來似乎是未完成品，所以無法調整輸出。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"제대로 된 형태만 갖춘다면, 우리의 대의를 이루는 데 큰 도움이 되겠어.","JPN":"ちゃんとモノにできれば、俺たちの大儀を成すのにさぞかし役に立つだろう。","ENG":"But if it gets completed in its proper form, it will greatly help us achieve our goal.","TWN":"要是能夠拿到完成品，對於完成我們的霸業會很有幫助。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"꼬마, 순순히 그 방패를 내려놔라.","JPN":"チビ、素直にその盾を下ろせ。","ENG":"Little one, put that shield down.","TWN":"小鬼，把你的盾牌交出來。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……가까이 오지 마요.","JPN":"……来ないで。","ENG":"....Don't come any closer.","TWN":"……別過來。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"당신들도 저 여자처럼 되고 싶어요?","JPN":"あなたたちもあの女みたいになりたいんですか？","ENG":"Do you want to end up like her?","TWN":"你們也想變得和那個女的一樣嗎？"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"벌벌 떨고 있는 주제에 허세 부리지 마라.","JPN":"ブルブル震えてるくせに、強がるな。","ENG":"Stop acting tough. We can see you are trembling.","TWN":"瞧你嚇得渾身發抖，還在那邊虛張聲勢。"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};